public void testGetTextBufferAfterAppend() {
    TextBuffer tb = new TextBuffer(new BufferRecycler());
    tb.append("test");
    char[] buf1 = tb.getTextBuffer();
    assertTrue(buf1.length >= 4);

    tb.resetWithEmpty();
    char[] buf2 = tb.getTextBuffer();
    assertTrue(buf2.length == 0);
}

public void testGetTextBufferWithResultString() {
    TextBuffer tb = new TextBuffer(new BufferRecycler());
    tb.append("hello");
    String str = tb.contentsAsString();
    char[] buf = tb.getTextBuffer();
    assertTrue(buf.length == 5);
    assertEquals("hello", new String(buf, 0, 5));
}

public void testGetTextBufferMultipleCalls() {
    TextBuffer tb = new TextBuffer(new BufferRecycler());
    tb.resetWithEmpty();
    tb.contentsAsString();

    char[] buf1 = tb.getTextBuffer();
    char[] buf2 = tb.getTextBuffer();
    assertTrue(buf1.length == 0);
    assertTrue(buf2.length == 0);
    assertSame(buf1, buf2);
}
